/** UsptWnpzDao.insert */
insert into uspt_wnpz
	(
		wnpz_id
		, member_id
		, wnpz_nm
		, acqdt
		, isu_instt
		, creator_id
		, created_dt
		, updater_id
		, updated_dt
	) values (
		#{wnpzId}
		, #{memberId}
		, #{wnpzNm}
		, #{acqdt}
		, #{isuInstt}
		, #{creatorId}
		, #{createdDt}
		, #{updaterId}
		, #{updatedDt}
	)

mapper.update:
/** UsptWnpzDao.update */
update uspt_wnpz
set
	wnpz_nm		= #{wnpzNm}
	, acqdt		= #{acqdt}
	, isu_instt = #{isuInstt}
	, updater_id = #{updaterId}
	, updated_dt = #{updatedDt}
where
	member_id = #{memberId}
	and wnpz_id = #{wnpzId}

